html:
{% set color = "#800080" %}
<style>
    .print-format th {
        background-color: {{color}} !important;
        color: #ffffff !important;
    }

    .brand-color {
        color: {{color}} !important;
    }

#background{
    position:absolute;
    z-index:0;
    background:white;
    display:block;
    min-height:50%; 
    min-width:50%;
    color:yellow;
    margin:0 auto;
    text-align:center;
    margin-left:80px;
    margin-top:120px;
}

#content{
    position:absolute;
    z-index:1;
}

#bg-text
{
    color:lightgrey;
    font-size:50px;
    transform:rotate(300deg);
    -webkit-transform:rotate(300deg);
}
</style>

{% if doc.submitted %}
<!--<div id="background">-->

<!--  <p id="bg-text">Duplicate</p>-->
<!--</div>-->
<!--<div id="content">-->

{% endif %}

<table style="width:100%; margin-bottom: 20px;">
    <tr>
        <td style="width:40%;">
            {% set company_letter = frappe.db.get_value("Company", doc.company, "default_letter_head") or 'Default' %}
            <img src="{{ frappe.db.get_value('Letter Head', company_letter, 'image')}}" class="img-fluid" style="height:60px">
        </td>
        <td style="width:40%; text-left:center; font-weight:bold;">
            <p style="line-height: 1.8; color: #800080;">
                <i class="fa fa-phone brand-color"></i> {{doc.company_phone or doc.contact_phone or ""}}<br>
                <i class="fa fa-envelope brand-color"></i> {{doc.company_email or doc.contact_email or ""}}<br>
                <i class="fa fa-map-marker brand-color"></i> {{doc.company_address_display or doc.address_display or ""}}
            </p>
        </td>
        <td style="width:20%; text-align:right;">
            <div class="text-right" style="width:80px">
                <img src='/files/barcodes/QRCode{{ doc.name|replace("#","%23") }}.svg'>
                <!--{% set domain = frappe.db.get_value("Global Defaults", "Global Defaults", "ip_or_domain") %}-->
                <!--<img src="https://api.qrserver.com/v1/create-qr-code/?size=150x150&data={{domain}}desk%23Form/Sales Invoice/{{doc.name}}">-->
                <!--<img src="https://api.qrserver.com/v1/create-qr-code/?size=150x150&data={{doc.company}}, {{doc.doctype}}, {{doc.get_formatted('posting_date') or doc.get_formatted('transaction_date')}}, {{doc.name}}">-->
            </div>
        </td>
    </tr>
</table>

<table style="width:100%; margin-bottom: 20px;">
    <tr> 
        <td style="text-align: left; font-size:20px; font-weight:700; padding-bottom: 10px; color: #800080;">{{ doc.company }}</td>
        <td style="float:right; font-size:20px; font-weight:700; padding-bottom: 10px; color: #800080;">SALES INVOICE</td>
    </tr>
    <tr style="padding:0px; margin:0px">
        <td style="padding:0px; margin:0px;"> 

            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Bill To</b></div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>{{doc.customer_name}}</b></div>

            {% set party = doc.customer %}
            {% set balance = 0 %}

            {% set query = frappe.db.get_all("GL Entry", filters={"party_type": 'Customer', "party": doc.customer, "posting_date": ("<=", doc.posting_date)},
            fields=["SUM(debit_in_account_currency) - SUM(credit_in_account_currency) as closing"]) %}

            {% if query %}
                {% set balance = query[0].closing %}
            {% endif %}

            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Previous Balance:</b> {{ "$ {:,.2f}".format(balance - doc.outstanding_amount)}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Phone:</b> {{doc.contact_mobile or doc.contact_phone or ""}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Current Balance:</b> {{ "$ {:,.2f}".format(balance or 0)}}</div>

        </td>
        <td style="float:right"> 
            <div class="" style="text-indent: 110px; margin-bottom: 8px; color: #800080;"><b>Username:</b> {{ frappe.db.get_value("User", doc.owner, "username") }}</div>
            {% set sales_person_name = "" %}
            {% set sales_contributions = frappe.db.get_all("Sales Team", filters={"parent": doc.name, "parenttype": "Sales Invoice"}, fields=["sales_person"], order_by="idx asc", limit=1) %}
            {% if sales_contributions and sales_contributions|length > 0 %}
                {% set sales_person_name = sales_contributions[0].sales_person %}
            {% endif %}
            <div class="" style="text-indent: 110px; margin-bottom: 8px; color: #800080;"><b>Sales Person:</b> {{ sales_person_name }}</div>
            <div class="" style="text-indent: 110px; margin-bottom: 8px; color: #800080;"><b>Series No:</b> {{doc.custom_invoice_no}}</div>
            <div class="" style="text-indent: 110px; margin-bottom: 8px; color: #800080;"><b>Invoice No:</b> {{doc.name}}</div>
            <div class="" style="text-indent: 110px; margin-bottom: 8px; color: #800080;"><b>Date:</b> {{doc.get_formatted("posting_date")}}</div>
            <div class="" style="text-indent: 110px; margin-bottom: 8px; color: #800080;"><b>Due Date:</b> {{doc.get_formatted("due_date")}}</div>
        </td>
    </tr>
</table>

<div class="" style="margin-top: 15px; margin-bottom: 15px;">
    <table class="custom_print" style="width:100%"> 
        <thead> 
            <tr> 
                <th style="width:1%; background-color: #800080; color: #ffffff;">No</th>
                <th style="width:14%; background-color: #800080; color: #ffffff;">Item Code</th>
                <th style="width:35%; background-color: #800080; color: #ffffff;">Item Name</th>
                <th style="width:10%; background-color: #800080; color: #ffffff;" class="text-right">Qty</th>
                <th style="width:12%; background-color: #800080; color: #ffffff;" class="text-right">Rate</th>
                <th style="width:13%; background-color: #800080; color: #ffffff;" class="text-right">Amount</th>
            </tr>
        </thead>
        {% for i in doc.items %}
        <tr style="color: #800080;">
            <td style="border-bottom: 1px solid; font-size: 10px; padding: 5px !important; color: #800080;">{{i.idx}}</td>
            <td style="border-bottom: 1px solid; font-size: 10px; padding: 5px !important; color: #800080;">{{i.item_code}}</td>
            <td style="border-bottom: 1px solid; font-size: 10px; padding: 5px !important; color: #800080;"><b>{{i.item_name}}</b></td>
            <td style="border-bottom: 1px solid; font-size: 10px; padding: 5px !important; color: #800080;" class="text-right">{{i.qty}}</td>
            <td style="border-bottom: 1px solid; font-size: 10px; padding: 5px !important; color: #800080;" class="text-right">{{i.get_formatted("rate")}}</td>
            <td style="border-bottom: 1px solid; font-size: 10px; padding: 5px !important; color: #800080;" class="text-right">{{i.get_formatted("amount")}}</td>
        </tr>
        {% endfor %}
    </table>
</div>

<table class="custom_print" style="width:100%; font-size: 10px; margin-top: 10px; margin-bottom: 20px;" border=1>
    <tr>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            Total Qty
        </td>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            Subtotal
        </td>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            Discount
        </td>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            Grand Total
        </td>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            VAT
        </td>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            Paid Amount
        </td>
        <td style="color:#ffffff; background:#800080; padding: 6px;" class="text-right">
            Balance
        </td>
    </tr>
    <tr style="color: #800080;">
        <td class="text-right" style="padding: 6px; color: #800080;">
            {{doc.get_formatted("total_qty")}}
        </td>
        <td class="text-right" style="padding: 6px; color: #800080;">
            {{doc.get_formatted("total")}}
        </td>
        <td class="text-right" style="padding: 6px; color: #800080;">
            {{doc.get_formatted("discount_amount")}}
        </td>
        <td class="text-right" style="padding: 6px; color: #800080;">
            {{doc.get_formatted("grand_total")}}
        </td>
        <td class="text-right" style="padding: 6px; color: #800080;">
            {{doc.get_formatted("total_taxes_and_charges")}}
        </td>
        <td class="text-right" style="padding: 6px; color: #800080;">
            {{doc.get_formatted("paid_amount")}}
        </td>
        <td class="text-right" style="padding: 6px; color: #800080;">
            <b>{{doc.get_formatted("outstanding_amount")}}</b>
        </td>
    </tr>
</table>

<table style="width:100%">
    <tr>
        <td style="font-size: 8px; color: #800080;">
            <b>Printed On: {{ frappe.utils.now_datetime().strftime("%a %d-%b-%Y %I:%M") }}</b>
        </td>
        <td style="text-align:right; font-size: 8px; color: #800080;">
            {% set username = frappe.db.get_value("User", frappe.session.user, "username") %}
            <b>Printed by: {{ username }}</b>
        </td>
    </tr>
</table>

{% if doc.submitted %}
<!--</div>-->
{% endif %}
